item.content:encoded:
@media ( min-width: 1199px) {
	.stretch-right .elementor-widget-container {
	   margin-right: calc( ( 100vw - 1140px)/-2);
  }
	.stretch-left .elementor-widget-container {
	   margin-left: calc( ( 100vw - 1140px)/-2);
  }	
}
.syd-contact  div.wpforms-container-full .wpforms-form button[type=submit] {
	width: 100%;
	display: block;
    color: #00102E;
    background: var(--sydney-global-color-1);	
	height: auto;
	  border: 0;
}
.grecaptcha-badge {visibility: hidden;}
.s-contact-form p,
.s-contact-form .row {
	margin-bottom: 40px;
}
.transparent-header .shfb-main_header_row:not(.sticky-active) {
	background-color: transparent;
}
.shfb .header-search-form {
	background-color: var(--sydney-global-color-6);
}
.footer-widget .widget-title {
    font-size: 16px;
    text-transform: uppercase;
}
.footer-widget ul {
	list-style: none;
	padding: 0;
}
.sticky-header-active .has-sticky-header .shfb-main_header_row {
	background-color: var(--sydney-global-color-6);
}
